import{_ as a,o as i,c as l,ag as t}from"./chunks/framework.D2Ob5GRY.js";const m=JSON.parse('{"title":"系统要求","description":"","frontmatter":{},"headers":[],"relativePath":"intro/system-requirements.md","filePath":"intro/system-requirements.md"}'),r={name:"intro/system-requirements.md"};function o(n,e,s,c,u,h){return i(),l("div",null,[...e[0]||(e[0]=[t('<h1 id="系统要求" tabindex="-1">系统要求 <a class="header-anchor" href="#系统要求" aria-label="Permalink to &quot;系统要求&quot;">​</a></h1><blockquote><p>部署 LinScio AI 前，请确认服务器硬件、操作系统与网络满足以下要求。</p></blockquote><h2 id="服务器硬件最低配置" tabindex="-1">服务器硬件最低配置 <a class="header-anchor" href="#服务器硬件最低配置" aria-label="Permalink to &quot;服务器硬件最低配置&quot;">​</a></h2><ul><li><strong>内存</strong>：8GB+，推荐 16GB+</li><li><strong>磁盘</strong>：30GB+ 可用空间，推荐 50GB+ SSD</li><li><strong>CPU</strong>：现代 x86_64 多核处理器</li></ul><h2 id="操作系统支持列表" tabindex="-1">操作系统支持列表 <a class="header-anchor" href="#操作系统支持列表" aria-label="Permalink to &quot;操作系统支持列表&quot;">​</a></h2><ul><li>Linux（推荐 Ubuntu 22.04 LTS、CentOS 7+、Debian 11+）</li><li>macOS（Intel / Apple Silicon，用于本地开发或单机使用）</li><li>Windows：建议通过 WSL2 或虚拟机运行 Linux 镜像</li></ul><h2 id="docker-版本要求" tabindex="-1">Docker 版本要求 <a class="header-anchor" href="#docker-版本要求" aria-label="Permalink to &quot;Docker 版本要求&quot;">​</a></h2><ul><li>Docker Engine 18.06+ 或 Docker Desktop 4.0+</li><li>若使用安装包方式，按安装包说明执行，可能无需单独安装 Docker</li></ul><h2 id="网络要求-llm-api-访问" tabindex="-1">网络要求（LLM API 访问） <a class="header-anchor" href="#网络要求-llm-api-访问" aria-label="Permalink to &quot;网络要求（LLM API 访问）&quot;">​</a></h2><ul><li>若使用云端 LLM（如 DeepSeek、OpenAI、通义、Gemini），服务器需能访问对应 API 域名；国内访问海外 API 时建议配置 HTTP/HTTPS 代理。</li><li>若仅使用本地 Ollama，可无需外网。</li></ul><h2 id="端口占用说明" tabindex="-1">端口占用说明 <a class="header-anchor" href="#端口占用说明" aria-label="Permalink to &quot;端口占用说明&quot;">​</a></h2><ul><li>主应用默认占用 <strong>8080</strong>（Web 界面与 API）。</li><li>数据库默认 <strong>5432</strong>（仅本地或 Docker 内网访问时可不必暴露）。</li></ul><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><ul><li><a href="/docs/quickstart/overview.html">快速开始概览</a></li><li><a href="/docs/quickstart/first-deployment.html">首次部署</a></li></ul>',14)])])}const k=a(r,[["render",o]]);export{m as __pageData,k as default};
